export const jogos = (): Promise<resumeFixture[]> => {
  const data = new Date();
  // usa ISO YYYY-MM-DD; adiciona 10 dias para o intervalo
  const hoje = data.toISOString().slice(0, 10);
  const dezDiasDate = new Date(data);
  dezDiasDate.setDate(data.getDate() + 10);
  const dezDias = dezDiasDate.toISOString().slice(0, 10);

  const qs = new URLSearchParams({
    league: "71",
    season: "2025",
    from: hoje,
    to: dezDias,
  });

  return fetch(`/api/bet?${qs.toString()}`)
    .then((r) => r.json())
    .then((json: Ifixture) => {
      return json.response.map((item) => {
        return {
          id: String(item.fixture.id),
          status: item.fixture.status.long,
          teams: {
            away: {
              logo: item.teams.away.logo,
              name: item.teams.away.name,
            },
            home: {
              logo: item.teams.home.logo,
              name: item.teams.home.name,
            },
          },
          goals: {
            home: item.goals.home ?? 0,
            away: item.goals.away ?? 0,
          },
          round: item.league.round,
          date: item.fixture.date,
        };
      });
    })
    .catch((err) => {
      console.error("[api/bet] fetch error:", err);
      return [];
    });
};

export type resumeFixture = {
  id: string;
  status: string;
  teams: {
    home: {
      name: string;
      logo: string;
    };
    away: {
      name: string;
      logo: string;
    };
  };
  goals: {
    home: number;
    away: number;
  };
  round: string;
  date: string;
};

export type Ifixture = {
  get: string;
  parameters: {
    league: string;
    season: string;
    from: string;
    to: string;
  };
  errors: Array<any>;
  results: number;
  paging: {
    current: number;
    total: number;
  };
  response: Array<{
    fixture: {
      id: number;
      referee?: string;
      timezone: string;
      date: string;
      timestamp: number;
      periods: {
        first?: number;
        second?: number;
      };
      venue: {
        id?: number;
        name: string;
        city: string;
      };
      status: {
        long: string;
        short: string;
        elapsed?: number;
        extra?: number;
      };
    };
    league: {
      id: number;
      name: string;
      country: string;
      logo: string;
      flag: string;
      season: number;
      round: string;
      standings: boolean;
    };
    teams: {
      home: {
        id: number;
        name: string;
        logo: string;
        winner?: boolean;
      };
      away: {
        id: number;
        name: string;
        logo: string;
        winner?: boolean;
      };
    };
    goals: {
      home?: number;
      away?: number;
    };
    score: {
      halftime: {
        home?: number;
        away?: number;
      };
      fulltime: {
        home?: number;
        away?: number;
      };
      extratime: {
        home: any;
        away: any;
      };
      penalty: {
        home: any;
        away: any;
      };
    };
  }>;
};
